// // This module implements a 4-bit binary counter that decrements its value on each clock cycle. The counter can be reset to zero or loaded with a specific 4-bit input value when the load signal is high. Upon a reset signal, the counter is initialized to zero. In each clock cycle, if the load signal is not asserted, the counter decrements its current value by one. The current count is output as a 4-bit register.
module top_module(
    input clk,
    input reset,
    input load,
    input [3:0] data_in,
    output reg [3:0] count
);reg [3:0] count_reg;
reg [3:0] count_next;

always @(posedge clk) begin
    if (reset) begin
        count_reg <= 4'b0;
    end
    else begin
        count_reg <= count_next;
    end
end

always @(*) begin
    if (load) begin
        count_next = data_in;
    end
    else begin
        count_next = count_reg + 4'b1;
    end
end

assign count = count_reg;

endmodule
